import Projection from"./Projection.js";import Units from"./Units.js";import{cosh}from"../math.js";const RADIUS=6378137,HALF_SIZE=Math.PI*RADIUS,EXTENT=[-HALF_SIZE,-HALF_SIZE,HALF_SIZE,HALF_SIZE],WORLD_EXTENT=[-180,-85,180,85],MAX_SAFE_Y=RADIUS*Math.log(Math.tan(Math.PI/2));class EPSG3857Projection extends Projection{constructor(t){super({code:t,units:Units.METERS,extent:EXTENT,global:!0,worldExtent:WORLD_EXTENT,getPointResolution:function(t,o){return t/cosh(o[1]/RADIUS)}})}}const PROJECTIONS=[new EPSG3857Projection("EPSG:3857"),new EPSG3857Projection("EPSG:102100"),new EPSG3857Projection("EPSG:102113"),new EPSG3857Projection("EPSG:900913"),new EPSG3857Projection("http://www.opengis.net/gml/srs/epsg.xml#3857")];function fromEPSG4326(E,t,o){var n=E.length,e=1<o?o:2;let S=t;void 0===S&&(S=2<e?E.slice():new Array(n));for(let o=0;o<n;o+=e){S[o]=HALF_SIZE*E[o]/180;let t=RADIUS*Math.log(Math.tan(Math.PI*(+E[o+1]+90)/360));t>MAX_SAFE_Y?t=MAX_SAFE_Y:t<-MAX_SAFE_Y&&(t=-MAX_SAFE_Y),S[o+1]=t}return S}function toEPSG4326(o,t,E){var n=o.length,e=1<E?E:2;let S=t;void 0===S&&(S=2<e?o.slice():new Array(n));for(let t=0;t<n;t+=e)S[t]=180*o[t]/HALF_SIZE,S[t+1]=360*Math.atan(Math.exp(o[t+1]/RADIUS))/Math.PI-90;return S}export{RADIUS,HALF_SIZE,EXTENT,WORLD_EXTENT,MAX_SAFE_Y,PROJECTIONS,fromEPSG4326,toEPSG4326};